// 5 LEDs flashing in sequence

const int LED_RED = 9;
const int LED_YELLOW = 10;
const int LED_GREEN = 11;
const int LED_BLUE = 12;
const int LED_PURPLE = 13;

const int DELAY_MS = 300;

void setup() {
  pinMode(LED_RED, OUTPUT);
  pinMode(LED_YELLOW, OUTPUT);
  pinMode(LED_GREEN, OUTPUT);
  pinMode(LED_BLUE, OUTPUT);
  pinMode(LED_PURPLE, OUTPUT);
}

void loop() {
  // Flash each LED in sequence
  digitalWrite(LED_RED, HIGH);
  delay(DELAY_MS);
  digitalWrite(LED_RED, LOW);

  digitalWrite(LED_YELLOW, HIGH);
  delay(DELAY_MS);
  digitalWrite(LED_YELLOW, LOW);

  digitalWrite(LED_GREEN, HIGH);
  delay(DELAY_MS);
  digitalWrite(LED_GREEN, LOW);

  digitalWrite(LED_BLUE, HIGH);
  delay(DELAY_MS);
  digitalWrite(LED_BLUE, LOW);

  digitalWrite(LED_PURPLE, HIGH);
  delay(DELAY_MS);
  digitalWrite(LED_PURPLE, LOW);

  delay(100); // Pause before next cycle
}

